parameters.jsCode:
// AI Agentから出力されたJSON形式の料理分析結果を取得します。
const analysisResult = $input.first().json.output;

// 結果が存在しない、または期待した形式でない場合はエラーを防ぐための処理
if (!analysisResult || !analysisResult.dishName) {
  return [{
    json: {
      subject: "料理分析エラー",
      htmlBody: "<p>AIによる分析結果を取得できませんでした。</p>"
    }
  }];
}

// 1. メールの件名を作成
const subject = `【料理分析レポート】 ${analysisResult.dishName}`;

// 2. HTMLメールの本文を生成
let htmlBody = `
<!DOCTYPE html>
<html lang="ja">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; line-height: 1.6; color: #333; background-color: #f9f9f9; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 20px auto; padding: 25px; background-color: #ffffff; border: 1px solid #e0e0e0; border-radius: 12px; box-shadow: 0 4px 8px rgba(0,0,0,0.05); }
    h1 { font-size: 26px; color: #2c3e50; border-bottom: 3px solid #3498db; padding-bottom: 10px; margin-top: 0; }
    h2 { font-size: 20px; color: #e74c3c; margin-bottom: 15px; }
    h3 { font-size: 18px; color: #34495e; margin-top: 30px; border-bottom: 1px solid #eeeeee; padding-bottom: 8px;}
    p { margin-top: 0; color: #555; }
    table { width: 100%; border-collapse: collapse; margin-top: 15px; }
    th, td { text-align: left; padding: 12px; border-bottom: 1px solid #dddddd; }
    th { background-color: #f2f2f2; color: #333; }
    tr:last-child td { border-bottom: none; }
    .total-calories { text-align: center; background-color: #fff3cd; padding: 15px; border-radius: 8px; margin-top: 20px; }
    .evaluation { background-color: #eafaf1; padding: 15px; border-left: 5px solid #2ecc71; border-radius: 5px; margin-top: 20px;}
    .footer { text-align: center; margin-top: 25px; font-size: 12px; color: #999; }
  </style>
</head>
<body>
  <div class="container">
    <h1>${analysisResult.dishName}</h1>

    <div class="total-calories">
      <h2>合計推定カロリー: ${analysisResult.totalCalories} kcal</h2>
    </div>

    <h3>詳細な食材リスト</h3>
    <table>
      <thead>
        <tr>
          <th>食材名</th>
          <th>分量 (g)</th>
          <th>カロリー (kcal)</th>
        </tr>
      </thead>
      <tbody>
`;

// 各食材の情報をテーブルの行として追加
if (analysisResult.ingredients && analysisResult.ingredients.length > 0) {
  analysisResult.ingredients.forEach(ingredient => {
    htmlBody += `
        <tr>
          <td>${ingredient.name}</td>
          <td>${ingredient.amount}</td>
          <td>${ingredient.calories}</td>
        </tr>
    `;
  });
}

htmlBody += `
      </tbody>
    </table>

    <h3>栄養バランスの評価</h3>
    <div class="evaluation">
      <p>${analysisResult.nutritionEvaluation}</p>
    </div>

    <div class="footer">
      <p>このレポートはAIによって自動生成されました。</p>
    </div>
  </div>
</body>
</html>
`;

// 3. 後続のGmailノードで使えるようにデータを返す
return [{
  json: {
    subject: subject,
    htmlBody: htmlBody
  }
}];

